import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(-1);
    const [isPlaying, setIsPlaying] = useState(false);
    const audioRef = useRef(null);

    // 1. Lấy danh sách bài hát
    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/songs');
                setSongs(res.data);
            } catch (err) { console.error(err); }
        };
        fetchSongs();
    }, []);

    // 2. Xử lý khi bấm nút PLAY trên danh sách
    const handleSelectSong = (index) => {
        setCurrentIndex(index);
        setIsPlaying(true);
    };

    // 3. Xử lý Phát / Tạm dừng
    const togglePlay = () => {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    };

    // 4. Xử lý bài tiếp theo (Next)
    const nextSong = () => {
        let next = (currentIndex + 1) % songs.length;
        setCurrentIndex(next);
        setIsPlaying(true);
    };

    // 5. Xử lý bài trước đó (Prev)
    const prevSong = () => {
        let prev = (currentIndex - 1 + songs.length) % songs.length;
        setCurrentIndex(prev);
        setIsPlaying(true);
    };

    const currentSong = songs[currentIndex];

    return (
        <div style={{ padding: '20px', maxWidth: '900px', margin: '0 auto', fontFamily: 'Arial', paddingBottom: '150px' }}>
            <h2 style={{ textAlign: 'center', marginBottom: '30px' }}>DANH SÁCH BÀI HÁT</h2>
            
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {songs.map((song, index) => (
                    <div key={song._id} style={{
                        display: 'flex', flexDirection: 'row', alignItems: 'center', padding: '12px 20px', 
                        border: '1px solid #eee', borderRadius: '12px',
                        background: currentIndex === index ? '#f0f7ff' : '#fff',
                        justifyContent: 'space-between'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center' }}>
                            <img src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/50'} 
                                 style={{ width: '50px', height: '50px', marginRight: '15px', borderRadius: '8px', objectFit: 'cover' }} />
                            <div style={{ textAlign: 'left' }}>
                                <div style={{ fontWeight: 'bold' }}>{song.title}</div>
                                <div style={{ fontSize: '13px', color: '#666' }}>{song.artist}</div>
                            </div>
                        </div>
                        <button onClick={() => handleSelectSong(index)} 
                                style={{ padding: '8px 20px', background: '#28a745', color: '#fff', border: 'none', borderRadius: '20px', cursor: 'pointer' }}>
                            NGHE
                        </button>
                    </div>
                ))}
            </div>

            {/* THANH ĐIỀU KHIỂN NHẠC NÂNG CAO */}
            {currentSong && (
                <div style={{
                    position: 'fixed', bottom: 0, left: 0, right: 0, 
                    background: '#181818', color: '#fff', padding: '15px 30px', 
                    display: 'flex', justifyContent: 'space-between', alignItems: 'center', zIndex: 1000,
                    boxShadow: '0 -5px 20px rgba(0,0,0,0.5)'
                }}>
                    {/* Bên trái: Thông tin bài hát đang phát */}
                    <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
                        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={{ width: '50px', height: '50px', borderRadius: '5px', marginRight: '15px' }} />
                        <div style={{ overflow: 'hidden' }}>
                            <div style={{ fontWeight: 'bold', whiteSpace: 'nowrap', textOverflow: 'ellipsis' }}>{currentSong.title}</div>
                            <div style={{ fontSize: '12px', color: '#b3b3b3' }}>{currentSong.artist}</div>
                        </div>
                    </div>

                    {/* Ở giữa: Nút điều khiển */}
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '40%' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '25px', marginBottom: '10px' }}>
                            <button onClick={prevSong} style={controlButtonStyle}>⏮</button>
                            <button onClick={togglePlay} style={{ ...controlButtonStyle, fontSize: '30px', background: '#fff', color: '#000', borderRadius: '50%', width: '50px', height: '50px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                {isPlaying ? '⏸' : '▶'}
                            </button>
                            <button onClick={nextSong} style={controlButtonStyle}>⏭</button>
                        </div>
                        <audio 
                            ref={audioRef}
                            src={`http://localhost:5000${currentSong.songUrl}`} 
                            autoPlay={isPlaying}
                            onEnded={nextSong} // Tự chuyển bài khi hết nhạc
                            style={{ width: '100%', height: '30px' }}
                            onPlay={() => setIsPlaying(true)}
                            onPause={() => setIsPlaying(false)}
                            controls // Bạn có thể bỏ controls này nếu muốn giao diện tối giản hơn
                        />
                    </div>

                    {/* Bên phải: Khoảng trống hoặc chỉnh âm lượng (tùy chọn) */}
                    <div style={{ width: '30%' }}></div>
                </div>
            )}
        </div>
    );
};

// Style cho các nút điều khiển
const controlButtonStyle = {
    background: 'none',
    border: 'none',
    color: '#fff',
    fontSize: '24px',
    cursor: 'pointer',
    transition: 'transform 0.2s',
};

export default Home;
